struct GoogleMapView: UIViewRepresentable {
    @Binding var center: CLLocationCoordinate2D
    @Binding var zoom: Float

    final class Coordinator: NSObject, GMSMapViewDelegate {
        var parent: GoogleMapView
        var marker: GMSMarker?

        init(_ parent: GoogleMapView) {
            self.parent = parent
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            parent.center = coordinate
            if marker == nil {
                let m = GMSMarker(position: coordinate)
                m.title = "Selected"
                m.snippet = "\(coordinate.latitude), \(coordinate.longitude)"
                m.map = mapView
                marker = m
            } else {
                marker?.position = coordinate
                marker?.snippet = "\(coordinate.latitude), \(coordinate.longitude)"
            }
        }

        func mapView(_ mapView: GMSMapView, idleAt position: GMSCameraPosition) {
            parent.center = position.target
            parent.zoom = position.zoom
        }
    }

    func makeCoordinator() -> Coordinator { Coordinator(self) }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withTarget: center, zoom: zoom)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.delegate = context.coordinator
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = false

        let marker = GMSMarker(position: center)
        marker.title = "Start"
        marker.snippet = "\(center.latitude), \(center.longitude)"
        marker.map = mapView
        context.coordinator.marker = marker

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        let current = uiView.camera
        let needsUpdate = abs(current.target.latitude - center.latitude) > 0.00001 ||
                          abs(current.target.longitude - center.longitude) > 0.00001 ||
                          abs(current.zoom - zoom) > 0.001

        if needsUpdate {
            let camera = GMSCameraPosition.camera(withTarget: center, zoom: zoom)
            uiView.animate(to: camera)
        }

        if context.coordinator.marker == nil {
            let marker = GMSMarker(position: center)
            marker.title = "Selected"
            marker.snippet = "\(center.latitude), \(center.longitude)"
            marker.map = uiView
            context.coordinator.marker = marker
        } else {
            context.coordinator.marker?.position = center
            context.coordinator.marker?.snippet = "\(center.latitude), \(center.longitude)"
        }
    }
}

