                    .font(.caption2)
                    .foregroundStyle(.secondary)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
        }
        .padding()
        .navigationTitle("Stripe")
        .navigationBarTitleDisplayMode(.inline)
        .sheet(isPresented: $isPresentingSheet) {
            PaymentSheetPresenter(paymentSheet: paymentSheet) { result in
                switch result {
                case .completed:
                    status = "Payment completed"
                case .canceled:
                    status = "Payment canceled"
                case .failed(let error):
                    status = "Payment failed: \(error.localizedDescription)"
                }
                isPresentingSheet = false
            }
        }
    }

    @MainActor
    private func prepareAndPresentPaymentSheet() async {
        status = "Creating PaymentIntent..."
        isPresentingSheet = true

        do {
            let response = try await DemoStripeBackend.createPaymentIntent(amount: amount, currency: currency.lowercased())
            var config = PaymentSheet.Configuration()
            config.merchantDisplayName = "Investor Demo"
            config.allowsDelayedPaymentMethods = false

            paymentSheet = PaymentSheet(paymentIntentClientSecret: response.paymentIntentClientSecret,
                                        configuration: config)
            status = "Presenting PaymentSheet..."
        } catch {
            status = "Error: \(error.localizedDescription)"
            isPresentingSheet = false
        }
    }
