struct PaymentSheetPresenter: UIViewControllerRepresentable {
    let paymentSheet: PaymentSheet?
    let onResult: (PaymentSheetResult) -> Void

    func makeUIViewController(context: Context) -> UIViewController {
        let vc = UIViewController()
        vc.view.backgroundColor = .clear
        return vc
    }

    func updateUIViewController(_ uiViewController: UIViewController, context: Context) {
        guard let paymentSheet else { return }
        DispatchQueue.main.async {
            paymentSheet.present(from: uiViewController) { result in
                onResult(result)
            }
        }
    }
}

// MARK: - Demo Backend (Replace with your backend)
// NOTE: Stripe requires a server-side secret key to create PaymentIntents.
// For a demo without your own backend, this uses Stripe's example endpoint pattern.
// Replace `baseURL` with your hosted demo server when available.
enum DemoStripeBackend {
    struct CreatePIResponse: Decodable {
        let paymentIntentClientSecret: String
    }

    enum BackendError: Error, LocalizedError {
        case invalidURL
        case invalidResponse
        case server(String)

        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid backend URL."
            case .invalidResponse: return "Invalid backend response."
            case .server(let message): return message
            }
        }
    }

    static var baseURL: String {
        // Replace with your own demo backend URL that creates PaymentIntents.
        // Example: "https://your-demo-backend.example.com"
        "https://stripe-mobile-payment-sheet.glitch.me"
    }

    static func createPaymentIntent(amount: Int, currency: String) async throws -> CreatePIResponse {
        guard let url = URL(string: "\(baseURL)/create-payment-intent") else { throw BackendError.invalidURL }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "amount": amount,
            "currency": currency
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body, options: [])

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let http = response as? HTTPURLResponse else { throw BackendError.invalidResponse }
        guard (200..<300).contains(http.statusCode) else {
            let message = String(data: data, encoding: .utf8) ?? "HTTP \(http.statusCode)"
            throw BackendError.server(message)
        }

        let decoded = try JSONDecoder().decode(CreatePIResponse.self, from: data)
        return decoded
    }
}